parameters.jsonBody:
{
  "parent": {
    "database_id": "{{ $credentials.notion.database_id }}"
  },
  "properties": {
    "Title": {
      "title": [
        {
          "text": {
            "content": "{{ $('Firecrawl Scraper').item.json.data.title }}"
          }
        }
      ]
    },
    "URL": {
      "url": "{{ $('Firecrawl Scraper').item.json.data.url }}"
    },
    "Status": {
      "select": {
        "name": "Generated"
      }
    },
    "Created": {
      "date": {
        "start": "{{ $now }}"
      }
    },
    "Content Types": {
      "multi_select": [
        {"name": "Blog Post"},
        {"name": "Twitter Thread"},
        {"name": "Newsletter"},
        {"name": "SEO Summary"}
      ]
    }
  }
}

{
  "text": "🚀 Content bundle ready for: {{ $('Firecrawl Scraper').item.json.data.title }}",
  "blocks": [
    {
      "type": "header",
      "text": {
        "type": "plain_text",
        "text": "Content Machine - Bundle Ready! 🎉"
      }
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Title:* {{ $('Firecrawl Scraper').item.json.data.title }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Source:* <{{ $('Firecrawl Scraper').item.json.data.url }}|View Original>"
        },
        {
          "type": "mrkdwn",
          "text": "*Generated:* {{ $now }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Content Types:* Blog Post, Twitter Thread, Newsletter, SEO Summary"
        }
      ]
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*Google Docs:*\n• <{{ $('Save Blog to Google Docs').item.json.documentId }}|Blog Post>\n• <{{ $('Save Twitter to Google Docs').item.json.documentId }}|Twitter Thread>"
      }
    }
  ]
}

parameters.responseBody:
{
  "success": true,
  "message": "Content bundle generated successfully",
  "title": "{{ $('Firecrawl Scraper').item.json.data.title }}",
  "url": "{{ $('Firecrawl Scraper').item.json.data.url }}",
  "timestamp": "{{ $now }}",
  "content_types": [
    "blog_post",
    "twitter_thread",
    "newsletter_summary",
    "seo_summary"
  ],
  "storage": {
    "google_docs": {
      "blog_post": "{{ $('Save Blog to Google Docs').item.json.documentId }}",
      "twitter_thread": "{{ $('Save Twitter to Google Docs').item.json.documentId }}"
    },
    "notion_page": "{{ $('Save to Notion Database').item.json.id }}"
  }
}
